sql:
SELECT patient_number, bmi
FROM patients
WHERE diabetes = 'Yes' AND bmi < (SELECT AVG(bmi) FROM patients);

SELECT patient_number
FROM patients
WHERE age > 50 AND cholesterol = (SELECT MAX(cholesterol) FROM patients WHERE age > 50);

SELECT AVG(age) AS average_age
FROM patients
WHERE diabetes_type = 'Unknown';

SELECT patient_number, bmi, diabetes, email
FROM patients
WHERE bmi > 25.0 AND diabetes = 'Yes';

SELECT DISTINCT patient_number
FROM patient_readings
WHERE systolic_bp > 120 AND diastolic_bp < 80;

SELECT patient_number, cholesterol, glucose, systolic_bp
FROM patient_readings
ORDER BY reading_date ASC;

SELECT patient_number, cholesterol
FROM patients
WHERE cholesterol > (SELECT AVG(cholesterol) FROM patients);

SELECT 
  (SELECT COUNT(*) FROM patients WHERE bmi > 25) AS OverweightPatientCount,
  (SELECT AVG(cholesterol) FROM patients WHERE age > 50 AND diabetes_type = 'Type 1') AS AvgCholesterolOfOver50Type1DiabetesPatients;

SELECT DISTINCT medication 
FROM patient_readings 
WHERE a1c > 6 AND activity_level = 'medium';

SELECT p.patient_number, p.cholesterol
FROM patients p
ORDER BY p.cholesterol ASC;
